fn check_parity(nums1: Vec<i64>, target_parity: i64) -> bool {
    let n = nums1.len();

    // For each index i, we must be able to choose a value for nums2[i] 
    // that matches the target_parity.

    for i in 0..n {
        let mut possible = false;

        // Option 1: nums2[i] = nums1[i]
        let p1 = (nums1[i] % 2 + 2) % 2; // Get parity (0 or 1)
        if p1 == target_parity {
            possible = true;
        }

        // Option 2: nums2[i] = nums1[i] - nums1[j], where j != i
        if !possible {
            for j in 0..n {
                if i != j {
                    let diff = nums1[i] - nums1[j];
                    let p2 = (diff % 2 + 2) % 2;
                    if p2 == target_parity {
                        possible = true;
                        break;
                    }
                }
            }
        }

        if !possible {
            // If for this index i, no choice leads to the required parity, 
            // then this target_parity is impossible for the whole array.
            return false;
